    72→				}
    73→			}
    74→			if len(in.FieldSelector.Requirements) > 0 {
    75→				ret.FieldSelectorRequirements, ret.FieldSelectorParsingErr = fieldSelectorAsSelector(in.FieldSelector.Requirements)
