    27→	utilerrors "k8s.io/apimachinery/pkg/util/errors"
    28→	"k8s.io/apiserver/pkg/authentication/user"
    29→	"k8s.io/apiserver/pkg/authorization/authorizer"
    30→	genericfeatures "k8s.io/apiserver/pkg/features"
    31→	utilfeature "k8s.io/apiserver/pkg/util/feature"
    32→	authorizationapi "k8s.io/kubernetes/pkg/apis/authorization"
    33→)
    34→
    35→// ResourceAttributesFrom combines the API object information and the user.Info from the context to build a full authorizer.AttributesRecord for resource access
    36→func ResourceAttributesFrom(user user.Info, in authorizationapi.ResourceAttributes) authorizer.AttributesRecord {
    37→	ret := authorizer.AttributesRecord{
    38→		User:            user,
    39→		Verb:            in.Verb,
    40→		Namespace:       in.Namespace,
    41→		APIGroup:        in.Group,
    42→		APIVersion:      matchAllVersionIfEmpty(in.Version),
    43→		Resource:        in.Resource,
    44→		Subresource:     in.Subresource,
    45→		Name:            in.Name,
    46→		ResourceRequest: true,
    47→	}
    48→
    49→	if utilfeature.DefaultFeatureGate.Enabled(genericfeatures.AuthorizeWithSelectors) {
    50→		if in.LabelSelector != nil {
    51→			if len(in.LabelSelector.RawSelector) > 0 {
    52→				labelSelector, err := labels.Parse(in.LabelSelector.RawSelector)
    53→				if err != nil {
    54→					ret.LabelSelectorRequirements, ret.LabelSelectorParsingErr = nil, err
    55→				} else {
    56→					requirements, _ /*selectable*/ := labelSelector.Requirements()
    57→					ret.LabelSelectorRequirements, ret.LabelSelectorParsingErr = requirements, nil
    58→				}
    59→			}
    60→			if len(in.LabelSelector.Requirements) > 0 {
    61→				ret.LabelSelectorRequirements, ret.LabelSelectorParsingErr = labelSelectorAsSelector(in.LabelSelector.Requirements)
    62→			}
    63→		}
    64→
    65→		if in.FieldSelector != nil {
    66→			if len(in.FieldSelector.RawSelector) > 0 {
    67→				fieldSelector, err := fields.ParseSelector(in.FieldSelector.RawSelector)
    68→				if err != nil {
    69→					ret.FieldSelectorRequirements, ret.FieldSelectorParsingErr = nil, err
    70→				} else {
    71→					ret.FieldSelectorRequirements, ret.FieldSelectorParsingErr = fieldSelector.Requirements(), nil
    72→				}
    73→			}
    74→			if len(in.FieldSelector.Requirements) > 0 {
    75→				ret.FieldSelectorRequirements, ret.FieldSelectorParsingErr = fieldSelectorAsSelector(in.FieldSelector.Requirements)
    76→			}
    77→		}
    78→	}
    79→
    80→	return ret
    81→}
    82→
    83→var labelSelectorOpToSelectionOp = map[metav1.LabelSelectorOperator]selection.Operator{
    84→	metav1.LabelSelectorOpIn:           selection.In,
    85→	metav1.LabelSelectorOpNotIn:        selection.NotIn,
    86→	metav1.LabelSelectorOpExists:       selection.Exists,
    87→	metav1.LabelSelectorOpDoesNotExist: selection.DoesNotExist,
    88→}
    89→
    90→func labelSelectorAsSelector(requirements []metav1.LabelSelectorRequirement) (labels.Requirements, error) {
    91→	if len(requirements) == 0 {
    92→		return nil, nil
    93→	}
    94→	reqs := make([]labels.Requirement, 0, len(requirements))
    95→	var errs []error
    96→	for _, expr := range requirements {
    97→		op, ok := labelSelectorOpToSelectionOp[expr.Operator]
    98→		if !ok {
    99→			errs = append(errs, fmt.Errorf("%q is not a valid label selector operator", expr.Operator))
   100→			continue
   101→		}
   102→		values := expr.Values
   103→		if len(values) == 0 {
   104→			values = nil
   105→		}
   106→		req, err := labels.NewRequirement(expr.Key, op, values)
   107→		if err != nil {
   108→			errs = append(errs, err)
   109→			continue
   110→		}
   111→		reqs = append(reqs, *req)
   112→	}
   113→
   114→	// If this happens, it means all requirements ended up getting skipped.
   115→	// Return nil rather than [].
   116→	if len(reqs) == 0 {
   117→		reqs = nil
   118→	}
   119→
   120→	// Return any accumulated errors along with any accumulated requirements, so recognized / valid requirements can be considered by authorization.
   121→	// This is safe because requirements are ANDed together so dropping unknown / invalid ones results in a strictly broader authorization check.
   122→	return labels.Requirements(reqs), utilerrors.NewAggregate(errs)
   123→}
   124→
   125→func fieldSelectorAsSelector(requirements []metav1.FieldSelectorRequirement) (fields.Requirements, error) {
   126→	if len(requirements) == 0 {
   127→		return nil, nil
   128→	}
   129→
   130→	reqs := make([]fields.Requirement, 0, len(requirements))
   131→	var errs []error
   132→	for _, expr := range requirements {
   133→		if len(expr.Values) > 1 {
   134→			errs = append(errs, fmt.Errorf("fieldSelectors do not yet support multiple values"))
   135→			continue
   136→		}
   137→
   138→		switch expr.Operator {
   139→		case metav1.FieldSelectorOpIn:
   140→			if len(expr.Values) != 1 {
   141→				errs = append(errs, fmt.Errorf("fieldSelectors in must have one value"))
   142→				continue
   143→			}
   144→			// when converting to fields.Requirement, use Equals to match how parsed field selectors behave
   145→			reqs = append(reqs, fields.Requirement{Field: expr.Key, Operator: selection.Equals, Value: expr.Values[0]})
   146→		case metav1.FieldSelectorOpNotIn:
   147→			if len(expr.Values) != 1 {
   148→				errs = append(errs, fmt.Errorf("fieldSelectors not in must have one value"))
   149→				continue
   150→			}
   151→			// when converting to fields.Requirement, use NotEquals to match how parsed field selectors behave
   152→			reqs = append(reqs, fields.Requirement{Field: expr.Key, Operator: selection.NotEquals, Value: expr.Values[0]})
   153→		case metav1.FieldSelectorOpExists, metav1.FieldSelectorOpDoesNotExist:
   154→			errs = append(errs, fmt.Errorf("fieldSelectors do not yet support %v", expr.Operator))
   155→			continue
   156→		default:
   157→			errs = append(errs, fmt.Errorf("%q is not a valid field selector operator", expr.Operator))
   158→			continue
   159→		}
   160→	}
   161→
   162→	// If this happens, it means all requirements ended up getting skipped.
   163→	// Return nil rather than [].
   164→	if len(reqs) == 0 {
   165→		reqs = nil
   166→	}
   167→
   168→	// Return any accumulated errors along with any accumulated requirements, so recognized / valid requirements can be considered by authorization.
   169→	// This is safe because requirements are ANDed together so dropping unknown / invalid ones results in a strictly broader authorization check.
   170→	return fields.Requirements(reqs), utilerrors.NewAggregate(errs)
   171→}
   172→
   173→// NonResourceAttributesFrom combines the API object information and the user.Info from the context to build a full authorizer.AttributesRecord for non resource access
   174→func NonResourceAttributesFrom(user user.Info, in authorizationapi.NonResourceAttributes) authorizer.AttributesRecord {
   175→	return authorizer.AttributesRecord{
   176→		User:            user,
   177→		ResourceRequest: false,
   178→		Path:            in.Path,
   179→		Verb:            in.Verb,
   180→	}
   181→}
   182→
   183→func convertToUserInfoExtra(extra map[string]authorizationapi.ExtraValue) map[string][]string {
   184→	if extra == nil {
   185→		return nil
   186→	}
   187→	ret := map[string][]string{}
   188→	for k, v := range extra {
   189→		ret[k] = []string(v)
   190→	}
   191→
   192→	return ret
   193→}
   194→
   195→// AuthorizationAttributesFrom takes a spec and returns the proper authz attributes to check it.
   196→func AuthorizationAttributesFrom(spec authorizationapi.SubjectAccessReviewSpec) authorizer.AttributesRecord {
   197→	userToCheck := &user.DefaultInfo{
   198→		Name:   spec.User,
   199→		Groups: spec.Groups,
   200→		UID:    spec.UID,
   201→		Extra:  convertToUserInfoExtra(spec.Extra),
   202→	}
   203→
   204→	var authorizationAttributes authorizer.AttributesRecord
   205→	if spec.ResourceAttributes != nil {
   206→		authorizationAttributes = ResourceAttributesFrom(userToCheck, *spec.ResourceAttributes)
   207→	} else {
   208→		authorizationAttributes = NonResourceAttributesFrom(userToCheck, *spec.NonResourceAttributes)
   209→	}
   210→
   211→	return authorizationAttributes
   212→}
   213→
   214→// matchAllVersionIfEmpty returns a "*" if the version is unspecified
   215→func matchAllVersionIfEmpty(version string) string {
   216→	if len(version) == 0 {
   217→		return "*"
   218→	}
   219→	return version
   220→}
   221→
   222→// BuildEvaluationError constructs the evaluation error string to include in *SubjectAccessReview status
   223→// based on the authorizer evaluation error and any field and label selector parse errors.
   224→func BuildEvaluationError(evaluationError error, attrs authorizer.AttributesRecord) string {
   225→	var evaluationErrors []string
   226→	if evaluationError != nil {
   227→		evaluationErrors = append(evaluationErrors, evaluationError.Error())
   228→	}
   229→	if reqs, err := attrs.GetFieldSelector(); err != nil {
   230→		if len(reqs) > 0 {
   231→			evaluationErrors = append(evaluationErrors, "spec.resourceAttributes.fieldSelector partially ignored due to parse error")
   232→		} else {
   233→			evaluationErrors = append(evaluationErrors, "spec.resourceAttributes.fieldSelector ignored due to parse error")
   234→		}
   235→	}
   236→	if reqs, err := attrs.GetLabelSelector(); err != nil {
   237→		if len(reqs) > 0 {
   238→			evaluationErrors = append(evaluationErrors, "spec.resourceAttributes.labelSelector partially ignored due to parse error")
   239→		} else {
   240→			evaluationErrors = append(evaluationErrors, "spec.resourceAttributes.labelSelector ignored due to parse error")
   241→		}
   242→	}
   243→	return strings.Join(evaluationErrors, "; ")
   244→}
